class ZKProver:
    def __init__(self, secret: int):
        self.secret = secret
        self.public = pow(g, secret, p)

    def generate_proof(self, challenge: int) -> Tuple[int, int]:
        r = secrets.randbelow(p - 1)
        commitment = pow(g, r, p)
        response = (r + challenge * self.secret) % (p - 1)
        return commitment, response

class ZKVerifier:
    def verify(self, public: int, commitment: int, response: int, challenge: int) -> bool:
        lhs = pow(g, response, p)
        rhs = (commitment * pow(public, challenge, p)) % p
        return lhs == rhs

