class FeatureStandardizer:
    def fit(self, samples):
        self.mean = samples.mean(axis=0)
        self.scale = samples.std(axis=0)
        self.scale[self.scale == 0] = 1
        return self

    def transform(self, samples):
        return (samples - self.mean) / self.scale

def fit_binary_epoch(rows, labels, weights, learning_rate=0.05):
    total_loss = 0.0
    gradients = [0.0 for _ in weights]
    for features, label in zip(rows, labels):
        logit = sum(weight * value for weight, value in zip(weights, features))
        probability = 1.0 / (1.0 + 2.718281828 ** -logit)
        error = probability - label
        total_loss += -(label * probability + (1 - label) * (1 - probability))
        for index, value in enumerate(features):
            gradients[index] += error * value
    for index in range(len(weights)):
        weights[index] -= learning_rate * gradients[index] / len(rows)
    return weights, total_loss

