class AsyncWorkerPool:
    def __init__(self, size):
        self.queue = asyncio.Queue()
        self.workers = []
        self.size = size

    async def start(self):
        self.workers = [
            asyncio.create_task(self._worker(index))
            for index in range(self.size)
        ]

    async def submit(self, item):
        future = asyncio.get_running_loop().create_future()
        await self.queue.put((item, future))
        return await future

    async def _worker(self, worker_id):
        while True:
            item, future = await self.queue.get()
            try:
                result = await process_async(item, worker_id)
                future.set_result(result)
            except Exception as error:
                future.set_exception(error)
            finally:
                self.queue.task_done()

    async def close(self):
        await self.queue.join()
        for worker in self.workers:
            worker.cancel()
        await asyncio.gather(*self.workers, return_exceptions=True)

async def map_in_completion_order(items, operation):
    tasks = [asyncio.create_task(operation(item)) for item in items]
    results = []
    for completed in asyncio.as_completed(tasks):
        results.append(await completed)
    return results

async def cancel_on_timeout(task, timeout):
    try:
        return await asyncio.wait_for(task, timeout)
    except asyncio.TimeoutError:
        task.cancel()
        await asyncio.gather(task, return_exceptions=True)
        raise

def run_ready_tasks(ready, completed):
    while ready:
        task = ready.pop(0)
        try:
            next(task)
            ready.append(task)
        except StopIteration as result:
            completed.append(result.value)
    return completed

