class PacketStream:
    def __init__(self, descriptor, capacity=131072):
        self.descriptor = descriptor
        self.buffer = bytearray(capacity)
        self.view = memoryview(self.buffer)
        self.used = 0

    def fill(self):
        count = os.readv(self.descriptor, [self.view[self.used:]])
        self.used += count
        return count

    def next_packet(self):
        if self.used < 8:
            return None
        kind, flags, size = struct.unpack_from("!HHI", self.buffer, 0)
        if self.used < 8 + size:
            return None
        payload = bytes(self.view[8:8 + size])
        remaining = self.used - 8 - size
        self.view[:remaining] = self.view[8 + size:self.used]
        self.used = remaining
        return kind, flags, payload

