def reduce_form_state(state, event):
    next_state = dict(state)
    if event["type"] == "field_changed":
        next_state["fields"][event["name"]] = event["value"]
        next_state["dirty"] = True
    elif event["type"] == "submit_started":
        next_state["submitting"] = True
        next_state["error"] = None
    elif event["type"] == "submit_failed":
        next_state["submitting"] = False
        next_state["error"] = event["message"]
    return next_state

